generated_oml:
// Enablers
instance SysMLModelingTool : DTDFVocab:Enabler [
    base:desc "SysML (ModelBased Systems Engineering) tool used for creating structural models of the motor and gearbox."
    DTDFVocab:enables RealTimeVisualizationService, TorqueComparisonService, FrictionModelIdentificationService, FrictionParameterExtractionService
]

instance MATLABSimulinkEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink used for simulation and data calculation models."
    DTDFVocab:enables RealTimeVisualizationService, TorqueComparisonService, FrictionModelIdentificationService, FrictionParameterExtractionService
]

instance MQTTBrokerInstance : DTDFVocab:Enabler [
    base:desc "MQTT broker facilitating real‑time sensor data streaming."
    DTDFVocab:enables RealTimeVisualizationService, TorqueComparisonService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing semantic linking of the digital shadow."
    DTDFVocab:enables RealTimeVisualizationService
]

instance UMLClassDiagramRef : DTDFVocab:Enabler [
    base:desc "Digital Shadow Reference Model represented as a UML class diagram."
    DTDFVocab:enables RealTimeVisualizationService
]

// Sensors
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "First axis controller current sensor measuring the input electrical current."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor side encoder providing angular position of the first rotary axis motor."
    DTDFVocab:producedData MotorSideEncoderDataTransmitted
]

instance GearboxSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Gearbox side encoder providing angular position of the gearbox output of the first rotary axis."
    DTDFVocab:producedData GearboxSideEncoderDataTransmitted
]

// Data transmitted via MQTT
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorSideEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorSideEncoder
]

instance GearboxSideEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSideEncoder
]

// Data derived from transmitted signals
instance CurrentData : DTDFVocab:Data [
    base:desc "Time‑stamped electrical current data from the first axis motor."
    DTDFVocab:inputTo MATLABSimulinkEngine
    DTDFVocab:fromData MotorCurrentDataTransmitted
]

instance MotorSideAngleData : DTDFVocab:Data [
    base:desc "Time‑stamped motor side encoder angular positions."
    DTDFVocab:inputTo MATLABSimulinkEngine
    DTDFVocab:fromData MotorSideEncoderDataTransmitted
]

instance GearboxSideAngleData : DTDFVocab:Data [
    base:desc "Time‑stamped gearbox side encoder angular positions."
    DTDFVocab:inputTo MATLABSimulinkEngine
    DTDFVocab:fromData GearboxSideEncoderDataTransmitted
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Derived torque calculated from motor current."
    DTDFVocab:inputTo MATLABSimulinkEngine
    DTDFVocab:fromData MotorCurrentDataTransmitted
]

instance DerivedVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity calculated from encoder angular positions."
    DTDFVocab:inputTo MATLABSimulinkEngine
    DTDFVocab:fromData MotorSideEncoderDataTransmitted
]

instance SimulationOutputData : DTDFVocab:Data [
    base:desc "Simulation outputs including torques, velocities, and friction model parameters."
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance FrictionModelParametersData : DTDFVocab:Data [
    base:desc "Derived friction model parameters for Coulomb‑Viscous, Stribeck, Dahl, and LuGre models."
    DTDFVocab:inputTo MATLABSimulinkEngine
]

// Models
instance MotorGearboxStructuralModel : DTDFVocab:Model [
    base:desc "SysML-based structural model of the motor and gearbox of the first rotary axis."
    DTDFVocab:inputTo SysMLModelingTool
]

instance MotorSimulinkModel : DTDFVocab:Model [
    base:desc "Executable Simulink model for the motor dynamics of the first rotary axis."
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance GearboxSimulinkModel : DTDFVocab:Model [
    base:desc "Executable Simulink model for the gearbox dynamics of the first rotary axis."
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance SystemSimulinkModel : DTDFVocab:Model [
    base:desc "Executable Simulink model for the combined motor and gearbox system of the first rotary axis."
    DTDFVocab:inputTo MATLABSimulinkEngine
]

// Services
instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Real-time visualization in a unified dashboard."
    DTDFVocab:provides RealTimeDashboardInsight
]

instance TorqueComparisonService : DTDFVocab:Service [
    base:desc "Comparison of measured versus simulated torques and velocities."
    DTDFVocab:provides TorqueVelocityComparisonInsight
]

instance FrictionModelIdentificationService : DTDFVocab:Service [
    base:desc "Continuous identification and updating of friction models."
    DTDFVocab:provides FrictionModelIdentificationInsight, WearTrendInsight
]

instance FrictionParameterExtractionService : DTDFVocab:Service [
    base:desc "Extraction of friction parameters for controller tuning."
    DTDFVocab:provides FrictionParameterExtractionInsight, ControllerTuningInsight, PathRepeatabilityInsight, FrictionLossVisualizationInsight
]

