instance FrictionModelIdentificationInsight : DTDFVocab:Insight [
    base:desc "Updated friction parameters derived from online identification."
]

instance WearTrendInsight : DTDFVocab:Insight [
    base:desc "Identification of wear trends from friction model parameter evolution."
