instance FrictionParameterExtractionInsight : DTDFVocab:Insight [
    base:desc "Extraction of friction parameters for controller tuning."
]

instance ControllerTuningInsight : DTDFVocab:Insight [
    base:desc "Guidance for controller tuning based on updated friction parameters."
]

instance PathRepeatabilityInsight : DTDFVocab:Insight [
    base:desc "Improved path repeatability and positional accuracy enabled by updated friction models."
]

instance FrictionLossVisualizationInsight : DTDFVocab:Insight [
    base:desc "Visualization of friction losses for maintenance planning."
]

// Actions
instance ControllerTuningAction : DTDFVocab:Action [
    base:desc "Automatic adjustment of controller parameters based on updated friction parameters."
    DTDFVocab:IsAutomatic true
]

instance MaintenancePlanningAction : DTDFVocab:Action [
    base:desc "Guided maintenance plan derived from wear trend analysis."
    DTDFVocab:IsAutomatic false
]

